async Task<IResult> HandleFileUpload(HttpRequest request, string targetPath, FileCategory category)
{
    if (!request.HasFormContentType)
    {
        return Results.BadRequest(new UploadResponse
        {
            Success = false,
            ErrorMessage = "Request must be multipart/form-data."
        });
    }

    var form = await request.ReadFormAsync();
    var file = form.Files.FirstOrDefault();

    if (file == null || file.Length == 0)
    {
        return Results.BadRequest(new UploadResponse
        {
            Success = false,
            ErrorMessage = "No file was uploaded or file is empty."
        });
    }

    var result = await SaveFile(file, targetPath, category);

    if (!result.Success)
    {
        return Results.BadRequest(new UploadResponse
        {
            Success = false,
            ErrorMessage = result.ErrorMessage
        });
    }

    return Results.Ok(new UploadResponse
    {
        Success = true,
        FilePath = result.FilePath,
        FileName = result.FileName,
        OriginalFileName = result.OriginalFileName,
        FileSize = result.FileSize,
        ContentType = result.ContentType
    });
}

async Task<UploadResult> SaveFile(IFormFile file, string targetPath, FileCategory category)
{
    var result = new UploadResult
    {
        OriginalFileName = file.FileName,
        FileSize = file.Length,
        ContentType = file.ContentType
    };

    var extension = Path.GetExtension(file.FileName).ToLowerInvariant();

    var validationError = FileValidator.Validate(file, category, extension);
    if (validationError != null)
    {
        result.Success = false;
        result.ErrorMessage = validationError;
        return result;
    }

    if (!FileValidator.ValidateFileSignature(file, extension))
    {
        result.Success = false;
        result.ErrorMessage = "File content does not match the file extension. Possible malicious file.";
        return result;
    }

    var uniqueFileName = $"{Guid.NewGuid():N}{extension}";
    var filePath = Path.Combine(targetPath, uniqueFileName);

    try
    {
        using (var stream = new FileStream(filePath, FileMode.Create))
        {
            await file.CopyToAsync(stream);
        }

        var relativePath = filePath.Replace(Path.Combine(Directory.GetCurrentDirectory(), "wwwroot"), "")
                                   .Replace("\\", "/");

        result.Success = true;
        result.FileName = uniqueFileName;
        result.FilePath = relativePath;
    }
    catch (Exception ex)
    {
        result.Success = false;
        result.ErrorMessage = $"Failed to save file: {ex.Message}";
    }

    return result;
}

FileCategory DetermineCategory(IFormFile file)
{
    var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
    if (FileValidator.AllowedImageExtensions.Contains(extension))
        return FileCategory.Avatar;
    return FileCategory.Document;
}

public enum FileCategory
{
    Avatar,
    Document
}

public static class FileValidator
{
    public static readonly string[] AllowedImageExtensions = { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp" };
    public static readonly string[] AllowedDocumentExtensions = { ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx", ".txt", ".csv", ".rtf" };

    public const long MaxAvatarSizeBytes = 5 * 1024 * 1024; // 5 MB
    public const long MaxDocumentSizeBytes = 25 * 1024 * 1024; // 25 MB

    private static readonly Dictionary<string, byte[][]> FileSignatures = new()
    {
        { ".jpg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
        { ".jpeg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
        { ".png", new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A } } },
        { ".gif", new[] { new byte[] { 0x47, 0x49, 0x46, 0x38 } } },
        { ".bmp", new[] { new byte[] { 0x42, 0x4D } } },
        { ".pdf", new[] { new byte[] { 0x25, 0x50, 0x44, 0x46 } } },
        { ".doc", new[] { new byte[] { 0xD0, 0xCF, 0x11, 0xE0, 0xA1, 0xB1, 0x1A, 0xE1 } } },
        { ".xls", new[] { new byte[] { 0xD0, 0xCF, 0x11, 0xE0, 0xA1, 0xB1, 0x1A, 0xE1 } } },
        { ".ppt", new[] { new byte[] { 0xD0, 0xCF, 0x11, 0xE0, 0xA1, 0xB1, 0x1A, 0xE1 } } },
        { ".docx", new[] { new byte[] { 0x50, 0x4B, 0x03, 0x04 } } },
        { ".xlsx", new[] { new byte[] { 0x50, 0x4B, 0x03, 0x04 } } },
        { ".pptx", new[] { new byte[] { 0x50, 0x4B, 0x03, 0x04 } } },
    };

    public static string? Validate(IFormFile file, FileCategory category, string extension)
    {
        if (string.IsNullOrEmpty(extension))
        {
            return "File must have an extension.";
        }

        var allowedExtensions = category == FileCategory.Avatar
            ? AllowedImageExtensions
            : AllowedDocumentExtensions;

        if (!allowedExtensions.Contains(extension))
        {
            return $"File type '{extension}' is not allowed. Allowed types: {string.Join(", ", allowedExtensions)}";
        }

        var maxSize = category == FileCategory.Avatar ? MaxAvatarSizeBytes : MaxDocumentSizeBytes;
        if (file.Length > maxSize)
        {
            return $"File size ({file.Length / (1024 * 1024.0):F2} MB) exceeds the maximum allowed size ({maxSize / (1024 * 1024)} MB).";
        }

        var fileName = Path.GetFileNameWithoutExtension(file.FileName);
        if (string.IsNullOrWhiteSpace(fileName))
        {
            return "Invalid file name.";
        }

        return null;
    }

    public static bool ValidateFileSignature(IFormFile file, string extension)
    {
        if (!FileSignatures.ContainsKey(extension))
        {
            return true;
        }

        using var reader = new BinaryReader(file.OpenReadStream());
        var signatures = FileSignatures[extension];
        var headerBytes = reader.ReadBytes(signatures.Max(s => s.Length));

        return signatures.Any(signature =>
            headerBytes.Length >= signature.Length &&
            headerBytes.Take(signature.Length).SequenceEqual(signature));
    }
}

